def get_db() -> sqlite3.Connection:
    conn = sqlite3.connect(DB_PATH)
    conn.row_factory = sqlite3.Row
    conn.executescript(
        """
        CREATE TABLE IF NOT EXISTS user_notes (
            username TEXT PRIMARY KEY,
            status TEXT,
            note TEXT,
            updated_at INTEGER NOT NULL
        );
        CREATE TABLE IF NOT EXISTS settings (
            key TEXT PRIMARY KEY,
            value TEXT
        );
        CREATE TABLE IF NOT EXISTS user_score_history (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            username TEXT NOT NULL,
            recorded_at INTEGER NOT NULL,
            window_days INTEGER NOT NULL,
            score INTEGER NOT NULL,
            classification TEXT NOT NULL,
            UNIQUE(username, recorded_at, window_days)
        );
        CREATE TABLE IF NOT EXISTS ip_geolocation (
            ip_address TEXT PRIMARY KEY,
            city TEXT,
            region TEXT,
            country TEXT,
            org TEXT,
            source TEXT,
            looked_up_at INTEGER NOT NULL
        );
        """
    )
    conn.commit()
    return conn


def ts_to_str(ts: Any) -> str:
    try:
        return datetime.fromtimestamp(int(ts)).strftime("%Y-%m-%d %H:%M")
    except Exception:
        return "-"


def score_class(score: int, likely_threshold: int | None = None, watch_threshold: int | None = None) -> str:
    likely_threshold = likely_threshold or int(get_setting("likely_threshold", "70"))
    watch_threshold = watch_threshold or int(get_setting("watch_threshold", "40"))
    if score >= likely_threshold:
        return "likely"
    if score >= watch_threshold:
        return "watch"
    return "normal"


def classify(score: int, likely_threshold: int | None = None, watch_threshold: int | None = None) -> str:
    likely_threshold = likely_threshold or int(get_setting("likely_threshold", "70"))
    watch_threshold = watch_threshold or int(get_setting("watch_threshold", "40"))
    if score >= likely_threshold:
        return "likely sharing"
    if score >= watch_threshold:
        return "watch"
    return "normal"


def css_class_for(score: int) -> str:
    return score_class(score)


