@app.route("/")
def dashboard():
    conn = get_db()

    session_users = conn.execute(
        """
        SELECT username, MAX(started_at) AS last_seen
        FROM sessions
        WHERE username IS NOT NULL AND username != ''
        GROUP BY username
        """
    ).fetchall()

    users_data = []
    for row in session_users:
        username = row["username"]
        score_1 = score_user_from_sessions(conn, username, 1)
        users_data.append(
            {
                "username": username,
                "last_seen": row["last_seen"],
                "score": score_1["score"],
            }
        )

    users_data.sort(key=lambda row: (-row["score"], -(int(row["last_seen"] or 0)), row["username"].lower()))

    recent_24h = conn.execute(
        """
        SELECT COUNT(*)
        FROM (
          SELECT a.*
          FROM alerts a
          JOIN (
              SELECT username, alert_type, MAX(created_at) AS max_created_at
              FROM alerts
              WHERE created_at >= strftime('%s','now') - 86400
              GROUP BY username, alert_type
          ) latest
            ON a.username = latest.username
           AND a.alert_type = latest.alert_type
           AND a.created_at = latest.max_created_at
        )
        """
    ).fetchone()[0]

    likely_threshold = int(get_setting("likely_threshold", "70"))
    watch_threshold = int(get_setting("watch_threshold", "40"))
    likely = sum(1 for r in users_data if r["score"] >= likely_threshold)
    watch = sum(1 for r in users_data if watch_threshold <= r["score"] < likely_threshold)
    users_count = len(users_data)

    table_rows = []
    for r in users_data[:10]:
        score = int(r["score"] or 0)
        table_rows.append(
            f"<tr>"
            f"<td><a href='{url_for('user_detail', username=r['username'])}'>{r['username']}</a></td>"
            f"<td><span class='badge {css_class_for(score)}'>{score} · {classify(score)}</span></td>"
            f"<td>{ts_to_str(r['last_seen'])}</td>"
            f"</tr>"
        )

    content = f"""
    <div class="grid">
      <div class="card"><div class="muted">Users seen</div><div class="stat">{users_count}</div></div>
      <div class="card"><div class="muted">Latest alerts in last 24h</div><div class="stat">{recent_24h}</div></div>
      <div class="card"><div class="muted">Likely sharing</div><div class="stat">{likely}</div></div>
      <div class="card"><div class="muted">Watch</div><div class="stat">{watch}</div></div>
    </div>

    <div class="section-title">Top users by 1-day threat</div>
    <div class="table-wrap">
      <table>
        <thead><tr><th>User</th><th>Status</th><th>Last seen</th></tr></thead>
        <tbody>{''.join(table_rows) or '<tr><td colspan="3">No users yet.</td></tr>'}</tbody>
      </table>
    </div>
    """
    return render_page("Dashboard", content)


@app.route("/users")
def users():
    conn = get_db()

    session_users = conn.execute(
        """
        SELECT username, MAX(started_at) AS last_seen
        FROM sessions
        WHERE username IS NOT NULL AND username != ''
        GROUP BY username
        ORDER BY username COLLATE NOCASE
        """
    ).fetchall()

    notes = {
        row["username"]: row
        for row in conn.execute("SELECT * FROM user_notes").fetchall()
    }

    latest_alerts = {
        row["username"]: row["last_alert"]
        for row in conn.execute(
            """
            SELECT username, MAX(created_at) AS last_alert
            FROM alerts
            GROUP BY username
            """
        ).fetchall()
    }

    table_rows = []
    for r in session_users:
        username = r["username"]
        score_1 = score_user_from_sessions(conn, username, 1)
        score_7 = score_user_from_sessions(conn, username, 7)
        score_14 = score_user_from_sessions(conn, username, 14)
        score_30 = score_user_from_sessions(conn, username, 30)

        note_row = notes.get(username)
        review_status = note_row["status"] if note_row else ""
        review_note = (note_row["note"] if note_row else "") or ""
        note_html = review_note[:120] + ("…" if len(review_note) > 120 else "") if review_note else "-"

        table_rows.append(
            {
                "username": username,
                "score_1": score_1,
                "score_7": score_7,
                "score_14": score_14,
                "score_30": score_30,
                "review_status": review_status or "-",
                "last_seen": r["last_seen"],
                "last_alert": latest_alerts.get(username),
                "note_html": note_html,
            }
        )

    table_rows.sort(
        key=lambda row: (
            -row["score_1"]["score"],
            -row["score_7"]["score"],
            -row["score_14"]["score"],
            -row["score_30"]["score"],
            -(int(row["last_seen"] or 0)),
            row["username"].lower(),
        )
    )

    rendered_rows = []
    for row in table_rows:
        rendered_rows.append(
            f"<tr>"
            f"<td><a href='{url_for('user_detail', username=row['username'])}'>{row['username']}</a></td>"
            f"<td><span class='badge {row['score_1']['css_class']}'>{row['score_1']['score']} · {row['score_1']['classification']}</span></td>"
            f"<td><span class='badge {row['score_7']['css_class']}'>{row['score_7']['score']} · {row['score_7']['classification']}</span></td>"
            f"<td><span class='badge {row['score_14']['css_class']}'>{row['score_14']['score']} · {row['score_14']['classification']}</span></td>"
            f"<td><span class='badge {row['score_30']['css_class']}'>{row['score_30']['score']} · {row['score_30']['classification']}</span></td>"
            f"<td>{row['review_status']}</td>"
            f"<td>{ts_to_str(row['last_seen'])}</td>"
            f"<td>{ts_to_str(row['last_alert']) if row['last_alert'] else '-'}</td>"
            f"<td>{row['note_html']}</td>"
            f"</tr>"
        )

    content = f"""
    <div class="section-title">Users</div>
    <div class="muted" style="margin-bottom:12px;">
      All users seen in session history, sorted by threat level from highest to lowest.
      The 1d column is treated as the most current signal, followed by 7d, 14d, and 30d.
    </div>
    <div class="table-wrap">
      <table>
        <thead>
          <tr>
            <th>User</th>
            <th>1d</th>
            <th>7d</th>
            <th>14d</th>
            <th>30d</th>
            <th>Review status</th>
            <th>Last seen</th>
            <th>Last alert</th>
            <th>Note</th>
          </tr>
        </thead>
        <tbody>{''.join(rendered_rows) or '<tr><td colspan="9">No users found.</td></tr>'}</tbody>
      </table>
    </div>
    """
    return render_page("Users", content)


